import{_ as t,a as e,M as r,o}from"./chunks/framework.BzjwFSRk.js";const g=JSON.parse('{"title":"Проектный подход в творчестве","description":"Цикл самомотивированной деятельности","frontmatter":{"title":"Проектный подход в творчестве","description":"Цикл самомотивированной деятельности","date":"2017-10-25","cover":"Project-wheel.png","youtube":"https://www.youtube.com/watch?v=5aSf6ik05aY"},"headers":[],"relativePath":"theory/system/projectapp/index.md","filePath":"theory/system/projectapp/index.md"}'),i={name:"theory/system/projectapp/index.md"};function n(l,a,s,p,h,d){return o(),e("div",null,[...a[0]||(a[0]=[r('<p>Более 6 лет мы исследовали самые различные грани творчества. Изучали как это делают другие: читали книги психологов и педагогов, перенимали опыт различных систем организации труда. Творили сами: рисовали картины, шили одежду, мастерили мебель. Помогали творить другим: проводили мастер-классы и воркшопы, устраивали лесной творческий лагерь и помогали наполнять творчеством программы фестивалей. В этом процессе мы выработали, опробовали и усовершенствовали новый максимально простой способ разбить любое творческое начинание на серию небольших понятных этапов.</p><p>Этот подход помогает легче начинать, увереннее продолжать и решительнее завершать любые творческие проекты. От вышивки до ювелирных изделий, от мебели до целых зданий — проектный подход помогает не застрять на пути, не потерять состояние потока и не бояться тишины, возникающей когда все начатое завершено, а новое еще не начиналось.</p><p>=======</p><h1 id="проектныи-подход-в-творчестве-и-в-жизни" tabindex="-1">Проектный подход в творчестве и в жизни <a class="header-anchor" href="#проектныи-подход-в-творчестве-и-в-жизни" aria-label="Permalink to &quot;Проектный подход в творчестве и в жизни&quot;">​</a></h1><h3 id="цикл-самомотивированнои-деятельности-как-модуляция-материи-и-энергии" tabindex="-1">Цикл самомотивированной деятельности как модуляция материи и энергии <a class="header-anchor" href="#цикл-самомотивированнои-деятельности-как-модуляция-материи-и-энергии" aria-label="Permalink to &quot;Цикл самомотивированной деятельности как модуляция материи и энергии&quot;">​</a></h3><h2 id="модуляции-и-резонансы" tabindex="-1">Модуляции и резонансы <a class="header-anchor" href="#модуляции-и-резонансы" aria-label="Permalink to &quot;Модуляции и резонансы&quot;">​</a></h2><p>Всякий творческий акт можно рассмотреть как встречу двух начал — сознания и материи, замысла и вещества, энергии и формы. С точки зрения физики между материей и энергией нет непреодолимой границы: это два состояния одного и того же. Но человеку удобно и естественно различать их, и именно в зазоре между ними разворачивается всё, что мы называем творчеством.</p><p>Если смотреть на творчество как на процесс модуляции — то есть наложения смысла, ритма и формы на поток свободной энергии, — то проект оказывается не бюрократической надстройкой над «настоящим» творческим порывом, а самой тканью, из которой этот порыв соткан. Модуляция без структуры рассеивается, не находя резонанса ни в материале, ни в зрителе, ни в самом авторе. Проектный подход — это способ вслушаться в собственный творческий импульс достаточно внимательно, чтобы дать ему форму, в которой он сможет резонировать: с материалом, с задачей, с другими людьми и с самим временем жизни автора.</p><p>Больше шести лет исследуя грани творчества — читая психологов и педагогов, перенимая опыт разных систем организации труда, работая руками и проводя мастер-классы и воркшопы — вырабатывается предельно простой способ разбить любое творческое начинание на серию небольших понятных этапов. Этот способ помогает легче начинать, увереннее продолжать и решительнее завершать любые творческие проекты — от вышивки до ювелирных изделий, от мебели до целых зданий. Он не даёт застрять на пути, не даёт потерять состояние потока и не даёт испугаться тишины, которая наступает, когда всё начатое завершено, а новое ещё не началось.</p><h2 id="два-полюса-сознание-и-материя" tabindex="-1">Два полюса: сознание и материя <a class="header-anchor" href="#два-полюса-сознание-и-материя" aria-label="Permalink to &quot;Два полюса: сознание и материя&quot;">​</a></h2><p>В основании всей модели лежит простейшее наблюдение. На самом крупном масштабе у любого творческого пути есть два полюса — идея и результат. Иногда всё под рукой: рук, знаний и материала хватает, и то, что возникло в голове, сразу обретает форму в веществе. Так рождённая в сознании идея напрямую превращается в материю. Но чаще между этими двумя полюсами пролегает путь, и именно устройство этого пути — предмет проектного подхода.</p><p>Между полюсами есть ещё и промежуток — пауза, в которой результат уже позади, а новое ещё не возникло. Удовлетворение, расслабление, праздность — необходимый штиль ума, когда утихает буря мыслей и дел. Именно в этой тишине улавливаются самые тонкие идеи и смыслы, и после освежающего перерыва легко браться за новое. Творчество не боится этой паузы — оно её включает в себя как часть ритма, как выдох между вдохами.</p><h2 id="три-периода-движение-энергии-внимания" tabindex="-1">Три периода: движение энергии внимания <a class="header-anchor" href="#три-периода-движение-энергии-внимания" aria-label="Permalink to &quot;Три периода: движение энергии внимания&quot;">​</a></h2><p>Между двумя полюсами энергия внимания движется не хаотично, а описывает узнаваемый цикл: от рассеянного созерцания — к сосредоточенному воплощению — и снова к рассеиванию. Это средний масштаб модели, промежуточный между самой общей парой «идея — результат» и более дробной картой этапов. Здесь важно не количество делений, а сама пульсация: внимание уходит вглубь замысла, затем разворачивается в действие, а затем снова отпускает себя на волю. Три периода — это ритм дыхания творческого процесса, который проступает и в самой короткой задаче, и в замысле, растянутом на годы.</p><h2 id="четыре-фазы-стороны-света-творческого-компаса" tabindex="-1">Четыре фазы: стороны света творческого компаса <a class="header-anchor" href="#четыре-фазы-стороны-света-творческого-компаса" aria-label="Permalink to &quot;Четыре фазы: стороны света творческого компаса&quot;">​</a></h2><p>Разбиение цикла на четыре фазы удобнее всего для коротких начинаний и быстрых итераций — там, где важна скорость реакции на меняющиеся условия. Времена года сменяют друг друга — фантазия, разработка, реализация, осмысление, и так же сменяются фазы творческого компаса.</p><p>Если человек отталкивается не от собственного внутреннего образа, а от внешних условий, тот же круг поворачивается на сорок пять градусов и превращается в известный с 1995 года цикл НОРД («наблюдение, ориентация, решение, действие») — модель, которую разработал военный теоретик Джон Бойд. НОРД описывается как самовоспроизводящийся и саморегулирующийся кибернетический цикл: любой процесс, соответствующий реальности, действует непрерывно, взаимодействуя со средой и учитывая обратную связь от неё. В основе идей Бойда лежат работы Жана Пиаже, Людвига фон Берталанфи, Томаса Куна, Майкла Полани, Норберта Винера и Грегори Бейтсона — то есть весь корпус системного мышления двадцатого века. Разработана эта петля была для армии США, где ключевым фактором победы оказывается не столько сила, сколько скорость и качество цикла принятия решений: кто быстрее и точнее проходит собственную петлю обратной связи, тот и опережает противника — или, если противника нет, саму меняющуюся среду.</p><p>В применении к творческим проектам акцент немного смещается — от наблюдения внешней обстановки к наделению уже имеющихся данных смыслом. Мы оцениваем достигнутое, представляем результаты окружающим и вместе отмечаем завершение очередного цикла. Творчество — это осознанное совершенствование действительности, а значит, следующий цикл начинается именно тогда, когда собраны оба ингредиента: понимание того, что есть, и представление о том, как это можно улучшить собственными усилиями. Если НОРД детерминирован внешними критериями успеха, то цикл фантазии, разработки, реализации и осмысления направляется изнутри — человеческим чувством прекрасного, — не теряя при этом связи с реальностью.</p><h2 id="шесть-стадии-работы-над-проектом" tabindex="-1">Шесть стадий работы над проектом <a class="header-anchor" href="#шесть-стадии-работы-над-проектом" aria-label="Permalink to &quot;Шесть стадий работы над проектом&quot;">​</a></h2><p>Ещё точнее цикл описывается шестью стадиями, в которых чередуются созерцание и действие: отдых как переключение и расслабление, образ как фиксация первых представлений, план как проработка и приготовления, работа как прямое целенаправленное действие, детали как осмысление прогресса и переосмысление процессов, и итоги — завершение и представление творческих результатов. Эта шестёрка удобна там, где четырёх фаз не хватает для планирования, а двенадцати шагов — уже избыточно много.</p><h2 id="двенадцать-шагов-дюжина-на-пути-от-идеи-до-воплощения" tabindex="-1">Двенадцать шагов: дюжина на пути от идеи до воплощения <a class="header-anchor" href="#двенадцать-шагов-дюжина-на-пути-от-идеи-до-воплощения" aria-label="Permalink to &quot;Двенадцать шагов: дюжина на пути от идеи до воплощения&quot;">​</a></h2><p>Двенадцать — число, выходящее за пределы объёма кратковременной памяти человека, в которую помещается лишь семь плюс-минус два объекта. Но это древняя, издавна освоенная человеком дюжина: двенадцать часов на циферблате, двенадцать месяцев в году, двенадцать нот в равномерной темперации. Число двенадцать делится и на два, и на три, и на четыре, и на шесть — потому оно так удобно как основание системы счисления, и потому же оно оказывается наиболее подробной и вместе с тем всё ещё обозримой картой творческого проекта.</p><p>Двенадцать шагов — это уже взгляд немного со стороны. Внутри самого процесса такой перспективы у человека, как правило, нет: удерживать в уме три-пять шагов назад и столько же шагов вперёд — уже вызов для психики, не говоря о состоянии потока, в котором забываешь обо всём, кроме того, чем занят сейчас. Именно поэтому так важны стратегия, тактика и методика — периодический выход в позицию наблюдателя собственной деятельности, с блокнотом, с куратором, с самим этим списком шагов.</p><ol><li><strong>Идея</strong> — мысль, предлагаемая к реализации. Размышляя о совершенстве, можно найти способ приблизиться к нему хотя бы на шаг: идеи буквально витают в воздухе, и их можно научиться замечать — наблюдая мир, играя словами, обнаруживая проблемы и решения, оставаясь открытым новому опыту.</li><li><strong>Название</strong> — текстовая формулировка идеи, первый акт модуляции: мысль обретает имя, а вместе с именем — первую устойчивую форму, за которую можно ухватиться в дальнейшей работе.</li><li><strong>Эскиз</strong> — зарисовка общих контуров идеи, первое приближение образа к материи, ещё не связывающее автора обязательствами, но уже дающее замыслу видимые очертания.</li><li><strong>Цели</strong> — особенности предполагаемых результатов проекта. Здесь замысел проверяется на точность, измеримость, достижимость, экологичность и своевременность. О замках в облаках можно долго мечтать без всякой возможности двинуться навстречу задуманному — но стоит сформулировать желаемое точнее, и сразу открываются новые пути.</li><li><strong>Задачи</strong> — глагольные описания действий, необходимых для реализации проекта: цель раскладывается на конкретные шаги, которые уже можно совершить.</li><li><strong>Возможности</strong> — необходимые и доступные инструменты, материалы и умения. Здесь замысел встречается с реальными ресурсами и обнаруживает, чего ему не хватает и что уже есть под рукой.</li><li><strong>Процесс</strong> — последовательная реализация спланированных задач, сама работа, в которой энергия внимания превращается в изменения материала.</li><li><strong>Анализ</strong> — постоянная перепроверка соответствия задуманных и реальных результатов, тот самый контур обратной связи, без которого проект рискует уйти в сторону от первоначального смысла.</li><li><strong>Улучшение</strong> — принятие новых решений на основе приобретённого практического опыта. Проект не линеен: он снова и снова возвращается к себе, уточняя форму по мере того, как материал сопротивляется или, наоборот, подсказывает.</li><li><strong>Произведение</strong> — осознанное завершение деятельности в результате достижения поставленных целей или принятого решения. Ключевая черта проекта — его конечность, и произведение фиксирует момент, когда движение к цели останавливается.</li><li><strong>Представление</strong> — делясь результатами проекта, мы предъявляем себя, получаем обратную связь и ощущаем значимость проделанной работы. Именно на этом шаге модуляция впервые встречает резонанс во внешнем мире — во взгляде, отклике, реакции другого человека.</li><li><strong>Радость</strong> — переключиться, отпраздновать, чтобы расслабиться и успокоить ум. Это тот же промежуток между полюсами, только теперь пройденный осознанно и заслуженно, — пауза, из которой родится следующий виток.</li></ol><p>Сложность проекта может расти со временем и в какой-то момент становится уже группой взаимосвязанных проектов — всё зависит от точки зрения, и эту точку можно откалибровать по текущей сложности задуманного. Одни и те же принципы работы проявляются и в получасовой задаче, и в крупном начинании, которое группа людей реализует месяцами. Это похоже на фрактал: как проект можно рассматривать и одно простое действие, и всю свою жизнь целиком. Важно лишь найти в этой бесконечности собственный удобный масштаб, позволяющий устойчиво направлять внимание и усилия.</p><h2 id="ремесло-мастерство-искусство-глубина-погружения" tabindex="-1">Ремесло, мастерство, искусство: глубина погружения <a class="header-anchor" href="#ремесло-мастерство-искусство-глубина-погружения" aria-label="Permalink to &quot;Ремесло, мастерство, искусство: глубина погружения&quot;">​</a></h2><p>Проектный подход не задаёт единственно верной глубины погружения в дело — он лишь даёт форму движению, а наполнение этой формы каждый выбирает сам. Накопление знаний и опыта, чтобы вообще начать что-то делать; пробы и ошибки, из которых постепенно рождается <strong>ремесло</strong> — умение предсказуемо получать нужный результат; углубление в качество и точность исполнения, из которого вырастает <strong>мастерство</strong> — виртуозность и общественное признание; и, наконец, момент, когда эстетика и выразительность произведения становятся важнее его практической пользы или цены, — территория <strong>искусства</strong>, где автор вкладывает в форму ценный смысл, ищущий живого отклика у аудитории.</p><p>Ремесло, мастерство и искусство — это не ступени в единственно верном порядке, а грани одного и того же процесса реализации творческих стремлений человека, между которыми можно свободно перемещаться в разных направлениях деятельности и в разные периоды жизни. Проектный цикл — та рамка, внутри которой любая из этих граней может развернуться и завершиться, оставив после себя не пустоту, а опыт и новую свободу для следующего цикла.</p><h2 id="материя-и-энергия-как-оси-творческои-карты" tabindex="-1">Материя и энергия как оси творческой карты <a class="header-anchor" href="#материя-и-энергия-как-оси-творческои-карты" aria-label="Permalink to &quot;Материя и энергия как оси творческой карты&quot;">​</a></h2><p>Полезно помнить и о том, из чего вообще складывается материал творчества. Любую творческую технологию можно расположить на оси, где с одной стороны — материя, с другой — энергия, и координата на этой оси определяется тем, в каком соотношении в конкретном ремесле сочетаются затраты материалов и затраты энергии. Хотя с точки зрения физики материя и энергия — вообще одно и то же, человеку удобно различать их, и именно в этом различении рождается ощутимое разнообразие творческих направлений — от работы с твёрдыми и твердеющими массами до тонкой игры со звуком, светом, жестом и словом.</p><p>Проектный подход работает одинаково по обе стороны этой оси: и там, где преобразуется вещество, и там, где преобразуется чистая энергия внимания, замысла, впечатления. Модуляция идеи в звук или свет требует того же цикла — идеи, эскиза, целей, процесса, — что и модуляция идеи в дерево или металл. Меняется материал, но не структура пути.</p><h2 id="зачем-нужен-проектныи-подход-в-жизни-в-целом" tabindex="-1">Зачем нужен проектный подход в жизни в целом <a class="header-anchor" href="#зачем-нужен-проектныи-подход-в-жизни-в-целом" aria-label="Permalink to &quot;Зачем нужен проектный подход в жизни в целом&quot;">​</a></h2><p>Задумать огромный проект жизни и воплощать его десятилетиями — поступок, на который способен далеко не каждый. Но понимание того, что достижение даже самых сложных целей можно разбить на относительно простые этапы, даёт человеку уверенность в значимости прилагаемых усилий. Любое творчество пульсирует проектами — от едва уловимой идеи и грубых набросков до полной реализации задуманного проходит и художник, и столяр, и керамист, и поэт. Обычно это приходит с опытом, и многие даже не осознают до конца свои собственные методики работы. Но глубокое понимание творческого процесса помогает не застревать и поступательно двигаться к намеченным целям.</p><p>По мере реализации разных проектов приходит понимание творческого цикла: раз за разом проходя его, человек обнаруживает себя обновлённым в обновлённом мире. И этот цикл становится лишь витком в удивительной спирали развития и самосовершенствования. Творчество способно заполнить любые заданные ему рамки, но искусство — это всегда выход за границы правил и норм. Неразрывный процесс можно делить на любое число этапов, шагов и фаз, пытаясь нащупать в нём чёткий ритм и порядок, но стоит помнить: препятствий для самореализации в действительности нет. Проект — не клетка для творческой энергии, а её резонатор: форма, в которой модуляция замысла способна состояться и быть услышанной — материалом, собой и миром.</p>',34)])])}const u=t(i,[["render",n]]);export{g as __pageData,u as default};
